// === Validate & Prepare ===
// Espera body con:
//   schedule_id, products[3]{name,url,prompt_override?},
//   references[2], aspect_ratio, resolution, video_duration, callback_url
const b = $input.first().json.body || $input.first().json;

if (!b || !Array.isArray(b.products) || b.products.length !== 3) {
  throw new Error('Se esperan exactamente 3 productos en body.products[]');
}
if (!Array.isArray(b.references) || b.references.length < 1) {
  throw new Error('Se esperan 1-2 imagenes de referencia en body.references[]');
}
if (!b.schedule_id) {
  throw new Error('schedule_id es requerido');
}

// Prompts default por producto (toman el plano de Saul si no hay override)
const DEFAULT_PROMPTS = {
  'AFTERBURN':  "HERO PRODUCT SHOT — IGNIS AFTERBURN (red slim can, silver calligraphic 'Ignis' logo, 250ml, 'Stay In Motion' tagline). PRODUCT LOCK: preserve EXACT can geometry, label, logo, typography from reference. SCENE: dynamic motion explosion of pomegranate burst with ginseng particles around the can. LIGHTING: cinematic rim red.",
  'BLACK CORE': "HERO PRODUCT SHOT — IGNIS BLACK CORE (matte black slim can, red calligraphic 'Ignis' logo, 250ml, 'Focus Is Power' tagline). PRODUCT LOCK: preserve EXACT can geometry. SCENE: dark cherry essence with caffeine matrix crystals floating. LIGHTING: moody noir red rim, deep blacks.",
  'OVERDRIVE':  "HERO PRODUCT SHOT — IGNIS OVERDRIVE (silver/metallic slim can, red calligraphic 'Ignis' logo, 250ml, 'Move Faster Than The Market' tagline). PRODUCT LOCK: preserve EXACT can geometry. SCENE: citrus electric splash with B-vitamins glow particles. LIGHTING: cinematic golden hour with chrome reflections."
};

const DEFAULT_VIDEO_PROMPT = "slow camera push-in towards the can, subtle product rotation, particles floating in slow motion, professional cinematography, 24fps";

const products = b.products.map((p, i) => ({
  index: i,
  name: p.name || `PRODUCT_${i+1}`,
  url: p.url,
  prompt: (p.prompt_override && p.prompt_override.trim()) || DEFAULT_PROMPTS[p.name] || `HERO PRODUCT SHOT — ${p.name}`,
  video_prompt: p.video_prompt_override || DEFAULT_VIDEO_PROMPT,
  save_path_image: p.save_path_image || `ignis/cat01/${p.name.toLowerCase().replace(/\s/g,'_')}_hero`,
  save_path_video: p.save_path_video || `ignis/cat01/${p.name.toLowerCase().replace(/\s/g,'_')}_hero_reel`,
}));

return [{
  json: {
    schedule_id: b.schedule_id,
    products,
    references: b.references,
    aspect_ratio: b.aspect_ratio || '1:1',
    resolution: b.resolution || '2K',
    output_format: b.output_format || 'png',
    video_duration: String(b.video_duration || 5),
    video_aspect_ratio: b.video_aspect_ratio || '1:1',
    callback_url: b.callback_url || ''
  }
}];

// === Generate 3 NanoBanana images in parallel with polling ===
// Cada imagen toma ~30-60s. En paralelo total ~60s.
const cfg = $input.first().json;
const KIE_BASE = 'https://api.kie.ai';
const KIE_API_KEY = $env.KIE_API_KEY;
if (!KIE_API_KEY) throw new Error('Falta variable de entorno KIE_API_KEY en n8n');

const headers = {
  'Authorization': `Bearer ${KIE_API_KEY}`,
  'Content-Type': 'application/json'
};

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function createTask(product) {
  // image_input = [imagen_producto, ...refs]. Maximo 8 segun KIE.
  const image_input = [product.url, ...cfg.references].slice(0, 8);
  const payload = {
    model: 'nano-banana-pro',
    input: {
      prompt: product.prompt,
      image_input,
      aspect_ratio: cfg.aspect_ratio,
      resolution: cfg.resolution,
      output_format: cfg.output_format
    }
  };
  const res = await fetch(`${KIE_BASE}/api/v1/jobs/createTask`, {
    method: 'POST', headers, body: JSON.stringify(payload)
  });
  const data = await res.json();
  if (data.code !== 200 || !data.data?.taskId) {
    throw new Error(`KIE create error para ${product.name}: ${data.msg || JSON.stringify(data)}`);
  }
  return data.data.taskId;
}

async function pollTask(taskId, productName, maxAttempts = 30, delayMs = 8000) {
  for (let i = 0; i < maxAttempts; i++) {
    await sleep(delayMs);
    const res = await fetch(`${KIE_BASE}/api/v1/jobs/recordInfo?taskId=${taskId}`, { headers });
    const data = await res.json();
    const d = data.data || {};
    const state = (d.state || d.status || '').toLowerCase();
    if (state === 'success' || state === 'succeeded') {
      const url = d.resultUrls?.[0] || d.resultJson?.resultUrls?.[0] || d.imageUrl || d.url;
      if (!url) throw new Error(`KIE success pero sin URL en ${productName}`);
      return { url, taskId, raw: d };
    }
    if (state === 'fail' || state === 'failed') {
      throw new Error(`KIE fail para ${productName}: ${d.failMsg || JSON.stringify(d)}`);
    }
    // sigue esperando: waiting, processing, queuing, etc.
  }
  throw new Error(`Timeout en NanoBanana para ${productName} (${maxAttempts * delayMs / 1000}s)`);
}

async function processProduct(product) {
  const taskId = await createTask(product);
  const result = await pollTask(taskId, product.name);
  return { ...product, image_taskId: taskId, image_url: result.url };
}

const results = await Promise.all(cfg.products.map(processProduct));

return [{
  json: {
    ...cfg,
    products: results
  }
}];

// === Generate 3 Kling videos in parallel ===
// Cada video toma ~90-180s. En paralelo total ~3min.
const cfg = $input.first().json;
const KIE_BASE = 'https://api.kie.ai';
const KIE_API_KEY = $env.KIE_API_KEY;

const headers = {
  'Authorization': `Bearer ${KIE_API_KEY}`,
  'Content-Type': 'application/json'
};

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function createVideoTask(product) {
  const payload = {
    model: 'kling-3.0/video',
    input: {
      mode: 'pro',
      sound: false,
      duration: cfg.video_duration,
      aspect_ratio: cfg.video_aspect_ratio,
      prompt: product.video_prompt,
      image_urls: [product.image_url],
      multi_shots: false
    }
  };
  const res = await fetch(`${KIE_BASE}/api/v1/jobs/createTask`, {
    method: 'POST', headers, body: JSON.stringify(payload)
  });
  const data = await res.json();
  if (data.code !== 200 || !data.data?.taskId) {
    throw new Error(`Kling create error para ${product.name}: ${data.msg || JSON.stringify(data)}`);
  }
  return data.data.taskId;
}

async function pollTask(taskId, productName, maxAttempts = 40, delayMs = 10000) {
  for (let i = 0; i < maxAttempts; i++) {
    await sleep(delayMs);
    const res = await fetch(`${KIE_BASE}/api/v1/jobs/recordInfo?taskId=${taskId}`, { headers });
    const data = await res.json();
    const d = data.data || {};
    const state = (d.state || d.status || '').toLowerCase();
    if (state === 'success' || state === 'succeeded') {
      const url = d.resultUrls?.[0] || d.resultJson?.resultUrls?.[0] || d.videoUrl || d.url;
      if (!url) throw new Error(`Kling success pero sin URL en ${productName}`);
      return { url, taskId, raw: d };
    }
    if (state === 'fail' || state === 'failed') {
      throw new Error(`Kling fail para ${productName}: ${d.failMsg || JSON.stringify(d)}`);
    }
  }
  throw new Error(`Timeout en Kling para ${productName} (${maxAttempts * delayMs / 1000}s)`);
}

async function processProduct(product) {
  const taskId = await createVideoTask(product);
  const result = await pollTask(taskId, product.name);
  return { ...product, video_taskId: taskId, video_url: result.url };
}

const results = await Promise.all(cfg.products.map(processProduct));

return [{
  json: {
    ...cfg,
    products: results
  }
}];

// === Build callback payload for the platform ===
const cfg = $input.first().json;

const outputs = [];
for (const p of cfg.products) {
  outputs.push({
    kind: 'image',
    product_name: p.name,
    storage_path: p.save_path_image,
    external_url: p.image_url,
    provider: 'kie.ai',
    model: 'nano-banana-pro',
    external_task_id: p.image_taskId,
    metadata: {
      aspect_ratio: cfg.aspect_ratio,
      resolution: cfg.resolution,
      prompt_used: p.prompt
    }
  });
  outputs.push({
    kind: 'video',
    product_name: p.name,
    storage_path: p.save_path_video,
    external_url: p.video_url,
    provider: 'kie.ai',
    model: 'kling-3.0/video',
    external_task_id: p.video_taskId,
    metadata: {
      duration: cfg.video_duration,
      aspect_ratio: cfg.video_aspect_ratio,
      first_frame_image_task_id: p.image_taskId,
      prompt_used: p.video_prompt
    }
  });
}

return [{
  json: {
    schedule_id: cfg.schedule_id,
    callback_url: cfg.callback_url,
    payload: {
      schedule_id: cfg.schedule_id,
      flow_slug: 'ignis-cat01-hero-ingredientes',
      outputs
    }
  }
}];
